mapper.select:
SELECT TBT.ID, TBT.COMPANY_ID, TBT.COMPANY_NAME, TBT.CUSTOMER_ID, TBT.CUSTOMER_NAME, TBT.PROCESS_CODE, TBT.PROCESS_NAME, CASE WHEN TDSI.ID IS NOT NULL THEN TDS.SHIP_NAME || '_' || TDSI.VOYAGE END SHIP_NAME_VOYAGE, CASE WHEN TDS.LEAVE_PORT_TIME IS NOT NULL THEN '1' ELSE '2' END "isLeave", TDS.LEAVE_PORT_TIME, TDS.BERTH_NAME, TDS.ID AS SHIPVOYAGE_ID, TDSI.ID AS SHIPVOYAGE_ITEM_ID, TDSI.TRADE_TYPE, MS.NET_WEIGHT, TDS.BERTH_TIME, TDS.LEAVE_BERTH_TIME, ( SELECT STATEMENT_NO FROM T_COST_STATEMENT TC_STATEMENT JOIN T_COST_STATEMENT_DETAIL TCSD ON TC_STATEMENT.ID = TCSD.STATEMENT JOIN T_COST_SHIP TC_SHIP ON (TC_SHIP.TYPE = '20' AND TCSD.BUSINESS_ID = TC_SHIP.ID) WHERE TC_STATEMENT."TYPE" = '40' AND TBT.ID = TC_SHIP.TRUST_ID AND ROWNUM <= 1 ) STATEMENT_NO, ( SELECT CREATE_BY_NAME FROM T_COST_SHIP TCS WHERE TCS."TYPE" = '20' AND TBT.ID = TCS.TRUST_ID AND ROWNUM <= 1 ) CREATE_BY_NAME, ( SELECT CREATE_TIME FROM T_COST_SHIP TCS WHERE TCS."TYPE" = '20' AND TBT.ID = TCS.TRUST_ID AND ROWNUM <= 1 ) CREATE_TIME, TBT.STATUS, MDD_TRUST_STATUS.DICT_LABEL STATUS_LABEL, CASE WHEN ( SELECT COUNT(1) FROM T_COST_SHIP TCS WHERE TCS."TYPE" = '20' AND TBT.ID = TCS.TRUST_ID ) < 1 THEN '00' ELSE ( CASE WHEN (SELECT MAX(TCST.ID) FROM T_COST_STATEMENT TCST INNER JOIN T_COST_STATEMENT_DETAIL TCSD ON TCST.ID = TCSD.STATEMENT INNER JOIN T_COST_SHIP TCS ON TCSD.BUSINESS_ID = TCS.ID WHERE TCS."TYPE" = '20' AND TCST.STATUS IN ('40','50') AND TBT.ID = TCS.TRUST_ID) IS NOT NULL THEN (SELECT TO_CHAR(MAX(TCST.STATUS)) FROM T_COST_STATEMENT TCST WHERE TCST.ID IN ( SELECT STATEMENT FROM T_COST_STATEMENT_DETAIL TCSD INNER JOIN T_COST_SHIP TCS ON TCSD.BUSINESS_ID = TCS.ID WHERE TCS."TYPE" = '20' AND TBT.ID = TCS.TRUST_ID )) ELSE ( SELECT TO_CHAR(STATUS) FROM T_COST_SHIP TCS WHERE TCS."TYPE" = '20' AND TBT.ID = TCS.TRUST_ID AND ROWNUM < 2 ) END ) END STATEMENT_STATUS, TDSI.CUSTOMER_ID AS SHIP_CUSTOMER_ID, TDSI.CUSTOMER_NAME AS SHIP_CUSTOMER_NAME, MDD.DICT_LABEL AS WORK_AREA_CD FROM T_BUS_TRUST TBT LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TBT.SHIPVOYAGE_ITEM_ID = TDSI.ID JOIN T_DIS_SHIPVOYAGE TDS ON TDSI.SHIPVOYAGE_ID = TDS.ID JOIN M_SHIP MS ON TDS.SHIP_ID = MS.ID JOIN M_DICT_DATA MDD_TRUST_STATUS ON ( MDD_TRUST_STATUS.DICT_TYPE = 'TRUST_STATUS' AND TBT.STATUS = MDD_TRUST_STATUS.DICT_VALUE ) LEFT JOIN M_BERTH MB ON TDS.BERTH_ID = MB.ID LEFT JOIN M_DICT_DATA MDD ON MDD.DICT_TYPE = 'WORK_AREA' AND MDD.DICT_VALUE = MB.WORK_AREA_CD
AND TBT.PROCESS_NAME IN ( '船舶加水', '接电' )
AND TBT.STATUS = #{status, jdbcType=VARCHAR}
AND TDSI.ID = #{shipvoyageItemId,jdbcType=BIGINT}
AND TBT.COMPANY_ID = #{companyId,jdbcType=BIGINT}
AND TDSI.CUSTOMER_ID = #{customerId,jdbcType=BIGINT}
AND TDS.SHIP_STATUS_CODE = #{shipStatusCode,jdbcType=VARCHAR}
AND TDS.LEAVE_BERTH_TIME >= #{beginLeaveBerthTime,jdbcType=TIMESTAMP}
AND TDS.LEAVE_BERTH_TIME <= #{endLeaveBerthTime,jdbcType=TIMESTAMP}
AND TDS.SHIP_STATUS_CODE != '120'
AND TDS.SHIP_STATUS_CODE = '120'
AND TDS.LEAVE_PORT_TIME >= #{beginLeavePortTime,jdbcType=TIMESTAMP}
AND TDS.LEAVE_PORT_TIME <= #{endLeavePortTime,jdbcType=TIMESTAMP}
AND TDS.SHIP_NAME LIKE #{shipName_like}
AND TDSI.VOYAGE LIKE #{voyage_like}
AND TBT.ID
NOT
IN (SELECT TCS.TRUST_ID FROM T_COST_SHIP TCS WHERE TCS."TYPE" = '20' AND TCS.TRUST_ID IS NOT NULL AND TCS.STATUS =#{statementStatus,jdbcType=VARCHAR}
AND TCS.ID NOT IN ( SELECT TCSD.BUSINESS_ID FROM T_COST_STATEMENT TCST INNER JOIN T_COST_STATEMENT_DETAIL TCSD ON TCST.ID = TCSD.STATEMENT WHERE TCST.STATUS IN ('40','50') AND TCSD.BUSINESS_ID IS NOT NULL )
)
AND TBT.ID IN ( SELECT TCS.TRUST_ID FROM T_COST_STATEMENT TCST INNER JOIN T_COST_STATEMENT_DETAIL TCSD ON TCST.ID = TCSD.STATEMENT INNER JOIN T_COST_SHIP TCS ON TCSD.BUSINESS_ID = TCS.ID WHERE TCS.TYPE = '20' AND TCST.STATUS = #{statementStatus,jdbcType=VARCHAR} )
AND MB.WORK_AREA_CD = '02'
AND (MB.WORK_AREA_CD = '01' OR MB.WORK_AREA_CD = '03')
ORDER BY LEAVE_PORT_TIME DESC

